  /* ═══════════════════════════════════
     STORE — All data reads/writes go
     through here. Keeps localStorage
     calls centralized and consistent.
  ═══════════════════════════════════ */
  const Store = {
    /** Load the full KPI database from localStorage */
    load() {
      try {
        const raw = localStorage.getItem(Config.STORAGE_KEY);
        return raw ? JSON.parse(raw) : {};
      } catch (err) {
        console.error('[Store] Failed to parse stored data:', err);
        return {};
      }
    },

    /** Persist the full database to localStorage */
    save(db) {
      try {
        localStorage.setItem(Config.STORAGE_KEY, JSON.stringify(db));
      } catch (err) {
        console.error('[Store] Failed to save data:', err);
        Toast.show('Failed to save data locally', 'error');
      }
    },

    /** Get the currently unlocked month for staff (set by admin) */
    getOpenMonth() {
      const stored = localStorage.getItem(Config.OPEN_MONTH_KEY);
      return stored !== null ? parseInt(stored, 10) : Config.CURRENT_MONTH;
    },

    /** Set which month staff can enter data for */
    setOpenMonth(monthIndex) {
      localStorage.setItem(Config.OPEN_MONTH_KEY, monthIndex);
    },

    /** Build the key used to store data for a specific dept/year/month */
    buildKey(deptId, year, month) {
      return `${deptId}-${year}-${month}`;
    },
  };

  /* ═══════════════════════════════════
     API — Handles all communication
     with the Google Apps Script backend.
     Wraps fetch() with try/catch and
     provides consistent error handling.
  ═══════════════════════════════════ */
  const API = {
    /** Fetch all saved KPI data from Google Sheets */
    async fetchAll() {
      try {
        const response = await fetch(`${Config.API_URL}?action=getAll`);
        if (!response.ok) throw new Error(`HTTP ${response.status}`);
        const json = await response.json();
        return json.data || null;
      } catch (err) {
        console.error('[API] fetchAll failed:', err);
        return null;
      }
    },

    /**
     * Push KPI data for a single dept/month to Google Sheets.
     * @param {string} deptId
     * @param {number} year
     * @param {number} month
     * @param {object} data  - { kpiId: value, ... }
     * @param {string} fileNames - comma-separated uploaded file names
     */
    async saveKPIs(deptId, year, month, data, fileNames = '') {
      try {
        const response = await fetch(Config.API_URL, {
          method: 'POST',
          body: JSON.stringify({ action: 'saveKPIs', dept: deptId, year, month, data, files: fileNames }),
        });
        if (!response.ok) throw new Error(`HTTP ${response.status}`);
        const json = await response.json();
        return json.success === true;
      } catch (err) {
        console.error('[API] saveKPIs failed:', err);
        return false;
      }
    },
  };

  /* ═══════════════════════════════════
     KPI UTILS — Pure calculation helpers.
     No DOM access — easily testable.
  ═══════════════════════════════════ */
  const KPIUtils = {
    /**
     * Compute MOH 4-level threshold status for a single KPI value.
     * Achievement % = (actual / target) * 100  for high-polarity
     *               = (target / actual) * 100  for low-polarity
     * Standard: ≥80%  |  Distress: 70–79%  |  Failing: 60–69%  |  Failed: <60%
     */
    getStatus(kpi, rawValue) {
      if (rawValue === '' || rawValue == null) return 'empty';
      const value = parseFloat(rawValue);
      if (isNaN(value)) return 'empty';

      let achievementPct;
      if (kpi.dir === 'high') {
        achievementPct = kpi.target > 0 ? (value / kpi.target) * 100 : 100;
      } else {
        // For low-polarity KPIs, being AT or BELOW target is 100% achievement
        achievementPct = value === 0 ? 100 : kpi.target > 0 ? (kpi.target / value) * 100 : 100;
      }

      if (achievementPct >= 80) return 'standard';
      if (achievementPct >= 70) return 'distress';
      if (achievementPct >= 60) return 'failing';
      return 'failed';
    },

    /** Map status string → CSS modifier class */
    getStatusClass(status) {
      return { standard: 'standard', distress: 'distress', failing: 'failing', failed: 'failed', empty: '' }[status] ?? '';
    },

    /** Map status string → CSS color value */
    getStatusColor(status) {
      return {
        standard: 'var(--color-green)',
        distress:  'var(--color-amber)',
        failing:   'var(--color-red)',
        failed:    'var(--color-crimson)',
        empty:     '#9ca3af',
      }[status] ?? '#9ca3af';
    },

    /** Map status string → human-readable label */
    getStatusLabel(status) {
      return { standard: 'Standard', distress: 'Distress', failing: 'Failing', failed: 'Failed', empty: 'No data' }[status] ?? '';
    },

    /** Get all KPIs for a department */
    getKPIsForDept(deptId) {
      return KPIS_BY_DEPT[deptId] ?? KPIS_BY_DEPT.ER;
    },

    /**
     * Calculate compliance score for a dept/month combination.
     * Returns { pct, counts: {standard,distress,failing,failed}, criticals, totalFilled }
     */
    calcDeptScore(deptId, month, db) {
      const key = Store.buildKey(deptId, Config.YEAR, month);
      const savedData = db[key] ?? {};
      const kpis = KPIUtils.getKPIsForDept(deptId);

      const counts = { standard: 0, distress: 0, failing: 0, failed: 0 };
      const criticals = [];
      let totalFilled = 0;

      kpis.forEach(kpi => {
        const status = KPIUtils.getStatus(kpi, savedData[kpi.id]);
        if (status !== 'empty') {
          totalFilled++;
          counts[status]++;
          if (status === 'failing' || status === 'failed') {
            criticals.push(kpi.name);
          }
        }
      });

      const pct = totalFilled > 0
        ? Math.round((counts.standard / totalFilled) * 100)
        : 0;

      return { pct, counts, criticals, totalFilled };
    },

    /**
     * Map a compliance % to a performance tier label.
     * Uses MOH Standard thresholds.
     */
    getPerfTier(pct, totalFilled) {
      if (totalFilled === 0) return 'nodata';
      if (pct >= 80) return 'standard';
      if (pct >= 70) return 'distress';
      if (pct >= 60) return 'failing';
      return 'failed';
    },

    getPerfLabel(tier) {
      return { standard: 'Standard', distress: 'Distress', failing: 'Failing', failed: 'Failed', nodata: 'No Data' }[tier] ?? '';
    },
  };

  /* ═══════════════════════════════════
     TOAST — Lightweight notification
     system for user feedback.
  ═══════════════════════════════════ */
  const Toast = {
    _timer: null,

    show(message, type = 'success') {
      const el = document.getElementById('toast');
      if (!el) return;

      // Clear any pending dismiss timer
      if (this._timer) clearTimeout(this._timer);

      el.textContent = message;
      el.className = `toast is-visible toast--${type}`;
      this._timer = setTimeout(() => el.classList.remove('is-visible'), 3500);
    },
  };

  /* ═══════════════════════════════════
     APP — Top-level screen navigation.
  ═══════════════════════════════════ */
  const App = {
    /** Switch to a screen by its HTML id */
    navigateTo(screenId) {
      document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));
      const target = document.getElementById(screenId);
      if (target) target.classList.add('active');

      // Initialize relevant screen on navigation
      if (screenId === 'screen-dept-select') DeptView.renderStaffGrid();
      if (screenId === 'screen-admin-app')   AdminApp.init();
    },
  };

  /* ═══════════════════════════════════
     DEPT VIEW — Renders department cards
     for both staff and admin views.
  ═══════════════════════════════════ */
  const DeptView = {
    renderStaffGrid() {
      this._renderGrid('dept-grid-staff', false);
    },

    renderAdminGrid() {
      this._renderGrid('dept-grid-admin', true);
    },

    _renderGrid(containerId, isAdminMode) {
      const container = document.getElementById(containerId);
      if (!container) return;
      container.innerHTML = DEPARTMENTS.map(dept => this._buildCard(dept, isAdminMode)).join('');
    },

    _buildCard(dept, isAdminMode) {
      const icon = DEPT_ICONS[dept.icon] ?? DEPT_ICONS.qm;
      const clickHandler = `KPIEntry.openDept('${dept.id}', ${isAdminMode})`;
      return `
        <div class="dept-card" onclick="${clickHandler}" role="button" tabindex="0"
          aria-label="Open ${dept.name} KPI form"
          onkeydown="if(event.key==='Enter')${clickHandler}">
          <div class="dept-card__icon">${icon}</div>
          <div class="dept-card__name">${dept.id}</div>
        </div>`;
    },
  };

  /* ═══════════════════════════════════
     KPI ENTRY — Handles the form for
     entering monthly KPI values.
  ═══════════════════════════════════ */
  const KPIEntry = {
    currentDeptId: null,
    isAdminMode: false,
    db: {},

    /** Open the entry form for a given department */
    openDept(deptId, isAdminMode) {
      // Check if admin has closed entry window for staff
      if (!isAdminMode && !Manage.isEntryOpen()) {
        Toast.show('Entry is currently closed. Please contact the admin.', 'error');
        return;
      }
      this.currentDeptId = deptId;
      this.isAdminMode = isAdminMode;
      this.db = Store.load();

      const dept = DEPARTMENTS.find(d => d.id === deptId);
      const entryMonth = this._getEntryMonth();

      // Update page header
      document.getElementById('kpi-entry-title').textContent = dept ? dept.name : deptId;
      document.getElementById('kpi-entry-month').textContent =
        `${Config.MONTHS_FULL[entryMonth]} ${Config.YEAR}`;

      // Configure back button destination
      const backBtn = document.getElementById('kpi-back-button');
      backBtn.onclick = isAdminMode
        ? () => AdminApp.navigateTo('entry')
        : () => App.navigateTo('screen-dept-select');

      // Clear uploaded files
      FileUpload.clear();

      App.navigateTo('screen-kpi-entry');
      this._renderForm();
    },

    /** Determine which month to use for data entry */
    _getEntryMonth() {
      // Admin can enter for any selected month; staff uses admin-controlled open month
      return this.isAdminMode ? AdminApp.selectedMonth : Store.getOpenMonth();
    },

    /** Render all KPI input rows */
    _renderForm() {
      const month = this._getEntryMonth();
      const key = Store.buildKey(this.currentDeptId, Config.YEAR, month);
      const savedData = this.db[key] ?? {};
      const kpis = KPIUtils.getKPIsForDept(this.currentDeptId);

      document.getElementById('kpi-form-list').innerHTML =
        kpis.map(kpi => this._buildKPIRow(kpi, savedData[kpi.id] ?? '')).join('');

      this._updateSummary();
    },

    _buildKPIRow(kpi, savedValue) {
      const status = KPIUtils.getStatus(kpi, savedValue);
      const statusClass = KPIUtils.getStatusClass(status);
      const color = KPIUtils.getStatusColor(status);
      const label = KPIUtils.getStatusLabel(status);
      const dirLabel = kpi.dir === 'high' ? '≥' : '≤';

      return `
        <div class="kpi-item kpi-item--${statusClass}" id="kpi-row-${kpi.id}">
          <div class="kpi-item__header">
            <div>
              <div class="kpi-item__name">${kpi.name}</div>
              <div class="kpi-item__target">Target: ${dirLabel}${kpi.target} ${kpi.unit}</div>
            </div>
            <div class="kpi-item__status-badge" id="kpi-badge-${kpi.id}">
              <span class="status-dot" style="background:${color}"></span>
              <span style="color:${color}">${label}</span>
            </div>
          </div>
          <div class="kpi-item__input-row">
            <input
              class="kpi-input"
              type="number"
              id="kpi-input-${kpi.id}"
              value="${savedValue}"
              placeholder="Enter value"
              min="0"
              step="any"
              oninput="KPIEntry.onValueChange('${kpi.id}')"
              aria-label="${kpi.name}"
            />
            <div class="kpi-item__current-value" id="kpi-value-${kpi.id}" style="color:${color}">
              ${savedValue !== '' ? `${savedValue} ${kpi.unit}` : '—'}
            </div>
          </div>
          <div class="kpi-item__error-msg" id="kpi-error-${kpi.id}"></div>
        </div>`;
    },

    /** Called on every keystroke — updates status indicators in real-time */
    onValueChange(kpiId) {
      const input = document.getElementById(`kpi-input-${kpiId}`);
      const value = input.value;
      const kpis = KPIUtils.getKPIsForDept(this.currentDeptId);
      const kpi = kpis.find(k => k.id === kpiId);
      if (!kpi) return;

      // Inline validation: value must be non-negative
      const errorEl = document.getElementById(`kpi-error-${kpiId}`);
      if (value !== '' && parseFloat(value) < 0) {
        input.classList.add('input-error');
        errorEl.textContent = 'Value cannot be negative';
        errorEl.classList.add('visible');
        return;
      }
      input.classList.remove('input-error');
      errorEl.classList.remove('visible');

      // Update row status
      const status = KPIUtils.getStatus(kpi, value);
      const color = KPIUtils.getStatusColor(status);
      const label = KPIUtils.getStatusLabel(status);

      const row = document.getElementById(`kpi-row-${kpiId}`);
      row.className = `kpi-item kpi-item--${KPIUtils.getStatusClass(status)}`;

      document.getElementById(`kpi-value-${kpiId}`).style.color = color;
      document.getElementById(`kpi-value-${kpiId}`).textContent =
        value !== '' ? `${value} ${kpi.unit}` : '—';

      document.getElementById(`kpi-badge-${kpiId}`).innerHTML = `
        <span class="status-dot" style="background:${color}"></span>
        <span style="color:${color}">${label}</span>`;

      this._updateSummary();
    },

    /** Validate all inputs before saving */
    _validateInputs() {
      const kpis = KPIUtils.getKPIsForDept(this.currentDeptId);
      let isValid = true;

      kpis.forEach(kpi => {
        const input = document.getElementById(`kpi-input-${kpiId}`);
        if (!input) return;
        const value = parseFloat(input.value);
        if (input.value !== '' && (isNaN(value) || value < 0)) {
          input.classList.add('input-error');
          isValid = false;
        }
      });

      return isValid;
    },

    /** Recalculate and update the 4-level summary counters */
    _updateSummary() {
      const kpis = KPIUtils.getKPIsForDept(this.currentDeptId);
      const counts = { standard: 0, distress: 0, failing: 0, failed: 0 };

      const month = this._getEntryMonth();
      const key = Store.buildKey(this.currentDeptId, Config.YEAR, month);
      const savedData = this.db[key] ?? {};

      kpis.forEach(kpi => {
        // Use live input value if available, otherwise fall back to saved
        const inputEl = document.getElementById(`kpi-input-${kpi.id}`);
        const value = inputEl ? inputEl.value : (savedData[kpi.id] ?? '');
        const status = KPIUtils.getStatus(kpi, value);
        if (status !== 'empty' && counts[status] !== undefined) counts[status]++;
      });

      document.getElementById('count-standard').textContent = counts.standard;
      document.getElementById('count-distress').textContent = counts.distress;
      document.getElementById('count-failing').textContent  = counts.failing;
      document.getElementById('count-failed').textContent   = counts.failed;
    },

    /** Save all KPI values for the current dept/month */
    async save() {
      const kpis = KPIUtils.getKPIsForDept(this.currentDeptId);
      const month = this._getEntryMonth();
      const key = Store.buildKey(this.currentDeptId, Config.YEAR, month);

      // Collect non-empty values
      const dataToSave = {};
      let hasValidationError = false;

      kpis.forEach(kpi => {
        const input = document.getElementById(`kpi-input-${kpi.id}`);
        if (!input) return;
        const value = input.value.trim();

        if (value !== '') {
          const numValue = parseFloat(value);
          if (isNaN(numValue) || numValue < 0) {
            input.classList.add('input-error');
            hasValidationError = true;
          } else {
            dataToSave[kpi.id] = value;
          }
        }
      });

      if (hasValidationError) {
        Toast.show('Please fix invalid values before saving', 'error');
        return;
      }

      // Optimistic local save — don't wait for network
      this.db[key] = dataToSave;
      Store.save(this.db);

      // UI: show loading state
      const saveBtn = document.getElementById('save-button');
      saveBtn.disabled = true;
      saveBtn.innerHTML = '<div class="spinner"></div> Saving...';

      // Attempt network sync to Google Sheets
      const fileNames = FileUpload.getFileNames();
      const syncSuccess = await API.saveKPIs(this.currentDeptId, Config.YEAR, month, dataToSave, fileNames);

      // UI: update button state
      saveBtn.disabled = false;

      if (syncSuccess) {
        saveBtn.classList.add('save-button--success');
        saveBtn.textContent = 'Saved';
        Toast.show('Data saved to Google Sheets', 'success');
      } else {
        saveBtn.textContent = 'Saved Locally';
        Toast.show('Saved locally — Sheets sync failed', 'info');
      }

      // Reset button after delay
      setTimeout(() => {
        saveBtn.classList.remove('save-button--success');
        saveBtn.textContent = 'Save Monthly Data';
      }, 2500);

      this._renderForm();
      // Show corrective plan form for any KPIs below standard
      CorrectivePlan.renderAfterSave(this.currentDeptId, month);
    },
  };

  /* ═══════════════════════════════════
     FILE UPLOAD — Drag, drop, and
     selection of supporting documents.
  ═══════════════════════════════════ */
  const FileUpload = {
    _files: [],

    handleDragOver(event) {
      event.preventDefault();
      document.getElementById('dropzone').classList.add('is-dragging');
    },

    handleDragLeave() {
      document.getElementById('dropzone').classList.remove('is-dragging');
    },

    handleDrop(event) {
      event.preventDefault();
      document.getElementById('dropzone').classList.remove('is-dragging');
      this._addFiles(Array.from(event.dataTransfer.files));
    },

    handleSelect(event) {
      this._addFiles(Array.from(event.target.files));
      event.target.value = ''; // Reset input so same file can be re-added
    },

    _addFiles(newFiles) {
      const maxBytes = Config.FILE_MAX_SIZE_MB * 1024 * 1024;

      newFiles.forEach(file => {
        if (file.size > maxBytes) {
          Toast.show(`${file.name} exceeds ${Config.FILE_MAX_SIZE_MB} MB limit`, 'error');
          return;
        }
        // Prevent duplicates
        if (!this._files.some(f => f.name === file.name)) {
          this._files.push(file);
        }
      });

      this._render();
    },

    remove(fileName) {
      this._files = this._files.filter(f => f.name !== fileName);
      this._render();
    },

    clear() {
      this._files = [];
      const container = document.getElementById('file-list');
      if (container) container.innerHTML = '';
    },

    getFileNames() {
      return this._files.map(f => f.name).join(', ');
    },

    _isImage(fileName) {
      return /\.(png|jpg|jpeg|gif|webp|bmp)$/i.test(fileName);
    },

    _render() {
      const container = document.getElementById('file-list');
      if (!container) return;

      container.innerHTML = this._files.map(file => `
        <div class="file-item">
          <div class="file-item__icon ${this._isImage(file.name) ? 'file-item__icon--image' : ''}">
            ${this._isImage(file.name)
              ? `<svg viewBox="0 0 24 24"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg>`
              : `<svg viewBox="0 0 24 24"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>`}
          </div>
          <div class="file-item__name" title="${file.name}">${file.name}</div>
          <div class="file-item__size">${(file.size / 1024).toFixed(0)} KB</div>
          <button class="file-item__remove" onclick="FileUpload.remove('${file.name}')"
            aria-label="Remove ${file.name}">
            <svg viewBox="0 0 24 24"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
          </button>
        </div>`).join('');
    },
  };

  /* ═══════════════════════════════════
     AUTH — Login and logout logic.
     Passwords are checked client-side
     (suitable for internal hospital tool).
  ═══════════════════════════════════ */
  const Auth = {
    login() {
      const passwordInput = document.getElementById('admin-password');
      const errorEl = document.getElementById('login-error');
      const enteredPassword = passwordInput.value;

      if (enteredPassword === Config.ADMIN_PASSWORD) {
        // Clear form on success
        errorEl.textContent = '';
        passwordInput.value = '';
        passwordInput.classList.remove('input-error');

        App.navigateTo('screen-admin-app');

        // Background sync from Google Sheets after login
        this._syncAfterLogin();
      } else {
        errorEl.textContent = 'Incorrect password';
        passwordInput.classList.add('input-error');
        setTimeout(() => passwordInput.classList.remove('input-error'), 1500);
      }
    },

    logout() {
      App.navigateTo('screen-landing');
    },

    async _syncAfterLogin() {
      const data = await API.fetchAll();
      if (data) {
        Store.save(data);
        // Refresh dashboard with fresh data
        AdminApp.db = data;
        AdminApp.renderDashboard();
        Toast.show('Synced from Google Sheets', 'success');
      }
    },
  };

  /* ═══════════════════════════════════
     ADMIN APP — Dashboard, data entry,
     and gap analysis for the admin.
  ═══════════════════════════════════ */
  const AdminApp = {
    selectedMonth: Config.CURRENT_MONTH,
    db: {},

    init() {
      this.db = Store.load();
      this._initOpenMonthControl();
      this._buildMonthTabs('dashboard-month-tabs', this.selectedMonth, month => {
        this.selectedMonth = month;
        this._syncMonthTabs(month);
        this.renderDashboard();
        
      });
      
      this._buildMonthTabs('plans-month-tabs', this.selectedMonth, month => {
        this.selectedMonth = month;
        this._syncMonthTabs(month);
        AdminPlans.selectedMonth = month;
        AdminPlans.render();
      });
      DeptView.renderAdminGrid();
      this.renderDashboard();
      
    },

    navigateTo(pageId) {
      document.querySelectorAll('.admin-page').forEach(p => p.classList.remove('is-active'));
      document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('is-active'));
      const page = document.getElementById(`page-${pageId}`);
      const nav = document.getElementById(`nav-${pageId}`);
      if (page) page.classList.add('is-active');
      if (nav) nav.classList.add('is-active');
      // Initialize manage page when opened
      if (pageId === 'manage') Manage.init();
      if (pageId === 'plans')  AdminPlans.init(AdminApp.selectedMonth);
    },

    setOpenMonth(monthIndex) {
      Store.setOpenMonth(parseInt(monthIndex, 10));
      const badge = document.getElementById('open-month-badge');
      if (badge) badge.textContent = `${Config.MONTHS_FULL[monthIndex]} — Open`;
    },

    _initOpenMonthControl() {
      const select = document.getElementById('open-month-select');
      const badge = document.getElementById('open-month-badge');
      if (!select) return;

      const currentOpen = Store.getOpenMonth();
      select.innerHTML = Config.MONTHS_SHORT
        .map((m, i) => `<option value="${i}" ${i === currentOpen ? 'selected' : ''}>${m}</option>`)
        .join('');

      if (badge) badge.textContent = `${Config.MONTHS_FULL[currentOpen]} — Open`;
    },

    _buildMonthTabs(containerId, activeMonth, onSelect) {
      const container = document.getElementById(containerId);
      if (!container) return;

      container.innerHTML = Config.MONTHS_SHORT
        .map((m, i) => `
          <button class="month-tab ${i === activeMonth ? 'is-active' : ''}"
            data-month="${i}">${m}</button>`)
        .join('');

      container.querySelectorAll('.month-tab').forEach(btn => {
        btn.addEventListener('click', () => {
          container.querySelectorAll('.month-tab').forEach(b => b.classList.remove('is-active'));
          btn.classList.add('is-active');
          onSelect(parseInt(btn.dataset.month, 10));
        });
      });
    },

    /** Keep both month tab groups in sync */
    _syncMonthTabs(month) {
      ['dashboard-month-tabs', 'plans-month-tabs'].forEach(id => {
        document.querySelectorAll(`#${id} .month-tab`).forEach((btn, i) => {
          btn.classList.toggle('is-active', i === month);
        });
      });
    },

    renderDashboard() {
      const activeDepts = DEPARTMENTS;
      let totalKPIs = 0, totalStandard = 0, totalDistressFailing = 0, totalFailed = 0;
      const allCriticals = [];

      const cards = activeDepts.map(dept => {
        const score = KPIUtils.calcDeptScore(dept.id, this.selectedMonth, this.db);
        const tier = KPIUtils.getPerfTier(score.pct, score.totalFilled);

        totalKPIs += score.totalFilled;
        totalStandard += score.counts.standard;
        totalDistressFailing += score.counts.distress + score.counts.failing;
        totalFailed += score.counts.failed;
        score.criticals.forEach(name => allCriticals.push({ dept: dept.name, kpi: name }));

        return this._buildDeptCard(dept, score, tier);
      }).join('');

      const grid = document.getElementById('dept-perf-grid');
      if (grid) grid.innerHTML = cards || '<div class="empty-state">No departments available</div>';

      const countEl = document.getElementById('dept-count');
      if (countEl) countEl.textContent = `${activeDepts.length} department${activeDepts.length !== 1 ? 's' : ''}`;

      // Update summary stats
      const avgPct = totalKPIs > 0 ? Math.round((totalStandard / totalKPIs) * 100) : 0;
      this._updateElement('stat-total', totalKPIs || '—');
      this._updateElement('stat-avg', totalKPIs > 0 ? `${avgPct}%` : '—');
      this._updateElement('stat-warn', totalDistressFailing);
      this._updateElement('stat-crit', totalFailed);

      // Color the avg stat based on performance tier
      const avgEl = document.getElementById('stat-avg');
      if (avgEl) {
        const tier = KPIUtils.getPerfTier(avgPct, totalKPIs);
        avgEl.className = `stat-card__value ${
          tier === 'standard' ? 'stat-card__value--teal' :
          tier === 'failed'   ? 'stat-card__value--red' :
          'stat-card__value--amber'
        }`;
      }

      // Show/hide critical alert strip
      const alertStrip = document.getElementById('alert-strip');
      const alertItems = document.getElementById('alert-items');
      if (alertStrip && alertItems) {
        if (allCriticals.length > 0) {
          alertStrip.classList.add('is-visible');
          alertItems.innerHTML = allCriticals
            .map(c => `<div class="alert-item"><span class="alert-dot"></span><strong>${c.dept}</strong> — ${c.kpi}</div>`)
            .join('');
        } else {
          alertStrip.classList.remove('is-visible');
        }
      }
    },

    _buildDeptCard(dept, score, tier) {
      const icon = DEPT_ICONS[dept.icon] ?? DEPT_ICONS.qm;
      const monthLabel = Config.MONTHS_FULL[this.selectedMonth];
      const pctDisplay = score.totalFilled > 0 ? `${score.pct}%` : '—';
      const noteText = score.criticals.length > 0
        ? `${score.criticals.length} critical KPI${score.criticals.length > 1 ? 's' : ''}`
        : 'All indicators within threshold';

      return `
        <div class="dept-perf-card"
          onclick="AdminApp.navigateTo('entry'); KPIEntry.openDept('${dept.id}', true)"
          role="button" tabindex="0"
          aria-label="${dept.name} performance: ${pctDisplay}">
          <div class="dept-perf-card__top">
            <div>
              <div style="margin-bottom:6px;display:flex">${icon}</div>
              <div class="dept-perf-card__name">${dept.name}</div>
            </div>
            <div class="perf-badge perf-badge--${tier}">${KPIUtils.getPerfLabel(tier)}</div>
          </div>
          <div class="dept-perf-card__pct dept-perf-card__pct--${tier}">${pctDisplay}</div>
          <div class="dept-perf-card__sub">${score.counts.standard} / ${score.totalFilled} KPIs met · ${monthLabel}</div>
          <div class="dept-perf-card__bar">
            <div class="dept-perf-card__bar-fill dept-perf-card__bar-fill--${tier}" style="width:${score.pct}%"></div>
          </div>
          <div class="dept-perf-card__note ${score.criticals.length > 0 ? 'is-critical' : ''}">${noteText}</div>
          <button onclick="event.stopPropagation();PDFExport.exportDept('${dept.id}', AdminApp.selectedMonth)"
            style="display:flex;align-items:center;gap:5px;margin-top:12px;padding:7px 12px;background:#f1f5f9;border:1px solid #e5e7eb;border-radius:7px;font-size:11px;font-weight:700;color:#374151;cursor:pointer;font-family:inherit;width:100%;justify-content:center">
            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
            Export PDF
          </button>
        </div>`;
    },


    /** Helper: safely update a DOM element's text content */
    _updateElement(id, value) {
      const el = document.getElementById(id);
      if (el) el.textContent = value;
    },
  };


  /* ═══════════════════════════════════
     PDF EXPORT — Generates a printable
     monthly KPI report per department.
     Opens in a new window → user saves
     as PDF via the browser print dialog.
  ═══════════════════════════════════ */
  const PDFExport = {

    LOGO: 'data:image/png;base64,',

    _statusColor(status) {
      return { standard:'#16a34a', distress:'#d97706', failing:'#dc2626', failed:'#7f1d1d', empty:'#9ca3af' }[status] ?? '#9ca3af';
    },

    _buildRow(kpi, val, fontSize) {
      const status  = KPIUtils.getStatus(kpi, val);
      const label   = KPIUtils.getStatusLabel(status);
      const color   = this._statusColor(status);
      const dir     = kpi.dir === 'high' ? '≥' : '≤';
      const display = val !== '' ? val + ' ' + kpi.unit : '—';
      const fs      = fontSize || 13;
      return `<tr>
        <td style="padding:9px 14px;border-bottom:1px solid #f0f0f0;font-size:${fs}px;color:#111827">${kpi.name}</td>
        <td style="padding:9px 14px;border-bottom:1px solid #f0f0f0;font-size:${fs}px;color:#6b7280;text-align:center">${dir}${kpi.target} ${kpi.unit}</td>
        <td style="padding:9px 14px;border-bottom:1px solid #f0f0f0;font-size:${fs + 1}px;font-weight:700;text-align:center;color:${color}">${display}</td>
        <td style="padding:9px 14px;border-bottom:1px solid #f0f0f0;text-align:center">
          <span style="background:${color}18;color:${color};font-size:10px;font-weight:700;padding:3px 10px;border-radius:20px">${label}</span>
        </td></tr>`;
    },

    _baseStyles() {
      return `
        @media print { @page { margin: 18mm 14mm; size: A4; } body { -webkit-print-color-adjust: exact; print-color-adjust: exact; } .no-print { display: none !important; } }
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body { font-family: 'Segoe UI', Arial, sans-serif; color: #111827; }
        .print-btn { display: block; margin: 0 auto 24px; padding: 12px 32px; background: #0d9488; color: #fff; border: none; border-radius: 8px; font-size: 14px; font-weight: 700; cursor: pointer; }
        .print-btn:hover { background: #0f9f92; }
      `;
    },

    _pageHeader(deptName, monthLabel) {
      return `
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:24px;padding-bottom:18px;border-bottom:2px solid #0d9488">
          <div style="display:flex;align-items:center;gap:14px">
            <img src="${this.LOGO}" style="width:52px;height:52px;object-fit:contain" alt="Logo"/>
            <div>
              <div style="font-size:15px;font-weight:700;color:#111827">Al-Methnab General Hospital</div>
              <div style="font-size:11px;color:#6b7280;margin-top:2px">Qassim Health Cluster</div>
            </div>
          </div>
          <div style="text-align:right">
            <div style="font-size:18px;font-weight:800;color:#0d9488">${deptName}</div>
            <div style="font-size:12px;color:#6b7280;margin-top:3px">KPI Monthly Report · ${monthLabel} ${Config.YEAR}</div>
            <div style="font-size:11px;color:#9ca3af;margin-top:2px">Generated: ${new Date().toLocaleDateString('en-GB')}</div>
          </div>
        </div>`;
    },

    _summaryChips(counts) {
      const chip = (val, lbl, bg, color) =>
        `<div style="flex:1;min-width:90px;background:${bg};border-radius:10px;padding:14px;text-align:center">
          <div style="font-size:26px;font-weight:800;line-height:1;color:${color}">${val}</div>
          <div style="font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.05em;color:${color};margin-top:4px">${lbl}</div>
        </div>`;
      return `<div style="display:flex;gap:10px;margin-bottom:22px;flex-wrap:wrap">
        ${chip(counts.standard, 'Standard', '#dcfce7', '#16a34a')}
        ${chip(counts.distress, 'Distress',  '#fef3c7', '#d97706')}
        ${chip(counts.failing,  'Failing',   '#fee2e2', '#dc2626')}
        ${chip(counts.failed,   'Failed',    '#fef2f2', '#7f1d1d')}
      </div>`;
    },

    /** Export one department */
    exportDept(deptId, month) {
      const dept = DEPARTMENTS.find(d => d.id === deptId);
      if (!dept) return;
      const db   = Store.load();
      const key  = Store.buildKey(deptId, Config.YEAR, month);
      const data = db[key] ?? {};
      const kpis = KPIUtils.getKPIsForDept(deptId);
      const ml   = Config.MONTHS_FULL[month];

      const counts = { standard:0, distress:0, failing:0, failed:0 };
      const rows   = kpis.map(kpi => {
        const s = KPIUtils.getStatus(kpi, data[kpi.id] ?? '');
        if (counts[s] !== undefined) counts[s]++;
        return this._buildRow(kpi, data[kpi.id] ?? '');
      }).join('');

      const html = `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"/>
        <title>KPI — ${dept.name} — ${ml} ${Config.YEAR}</title>
        <style>${this._baseStyles()}</style></head><body>
        <div style="max-width:800px;margin:0 auto;padding:32px 28px">
          <button class="print-btn no-print" onclick="window.print()">Save as PDF / Print</button>
          ${this._pageHeader(dept.name, ml)}
          ${this._summaryChips(counts)}
          <div style="border:1px solid #e5e7eb;border-radius:10px;overflow:hidden;margin-bottom:28px">
            <table style="width:100%;border-collapse:collapse">
              <thead><tr style="background:#0d9488">
                <th style="padding:12px 14px;text-align:left;font-size:11px;font-weight:700;color:#fff;text-transform:uppercase;letter-spacing:.04em;width:44%">KPI Name</th>
                <th style="padding:12px 14px;text-align:center;font-size:11px;font-weight:700;color:#fff;text-transform:uppercase;letter-spacing:.04em;width:18%">Target</th>
                <th style="padding:12px 14px;text-align:center;font-size:11px;font-weight:700;color:#fff;text-transform:uppercase;letter-spacing:.04em;width:18%">Value</th>
                <th style="padding:12px 14px;text-align:center;font-size:11px;font-weight:700;color:#fff;text-transform:uppercase;letter-spacing:.04em;width:20%">Status</th>
              </tr></thead>
              <tbody>${rows}</tbody>
            </table>
          </div>
          <div style="text-align:center;padding-top:16px;border-top:1px solid #e5e7eb;font-size:11px;color:#9ca3af">
            Al-Methnab General Hospital — KPI Platform · Built by Anhal Mohammad
          </div>
        </div></body></html>`;

      const win = window.open('', '_blank');
      win.document.write(html);
      win.document.close();
    },

    /** Export ALL departments for one month */
    exportAll(month) {
      const db = Store.load();
      const ml = Config.MONTHS_FULL[month];

      const sections = DEPARTMENTS.map(dept => {
        const key  = Store.buildKey(dept.id, Config.YEAR, month);
        const data = db[key] ?? {};
        const kpis = KPIUtils.getKPIsForDept(dept.id);
        const filled = kpis.filter(k => data[k.id] !== undefined && data[k.id] !== '').length;
        if (filled === 0) return '';

        const rows = kpis.map(k => this._buildRow(k, data[k.id] ?? '', 12)).join('');
        return `<div style="margin-bottom:24px;page-break-inside:avoid">
          <div style="background:#0d9488;color:#fff;padding:9px 14px;border-radius:8px 8px 0 0;font-size:13px;font-weight:700">${dept.name}</div>
          <table style="width:100%;border-collapse:collapse;border:1px solid #e5e7eb;border-top:none">
            <thead><tr style="background:#f9fafb">
              <th style="padding:8px 12px;text-align:left;font-size:11px;color:#374151;border-bottom:1px solid #e5e7eb">KPI</th>
              <th style="padding:8px 12px;text-align:center;font-size:11px;color:#374151;border-bottom:1px solid #e5e7eb">Target</th>
              <th style="padding:8px 12px;text-align:center;font-size:11px;color:#374151;border-bottom:1px solid #e5e7eb">Value</th>
              <th style="padding:8px 12px;text-align:center;font-size:11px;color:#374151;border-bottom:1px solid #e5e7eb">Status</th>
            </tr></thead>
            <tbody>${rows}</tbody>
          </table>
        </div>`;
      }).join('');

      const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"/>
        <title>Full KPI Report — ${ml} ${Config.YEAR}</title>
        <style>${this._baseStyles()}</style></head><body>
        <div style="max-width:800px;margin:0 auto;padding:32px 28px">
          <button class="print-btn no-print" onclick="window.print()">Save as PDF / Print</button>
          <div style="display:flex;align-items:center;gap:14px;margin-bottom:24px;padding-bottom:18px;border-bottom:2px solid #0d9488">
            <img src="${this.LOGO}" style="width:52px;height:52px;object-fit:contain"/>
            <div>
              <div style="font-size:17px;font-weight:800;color:#0d9488">Al-Methnab General Hospital</div>
              <div style="font-size:12px;color:#6b7280">Full KPI Report · ${ml} ${Config.YEAR} · Qassim Health Cluster</div>
            </div>
          </div>
          ${sections || '<p style="color:#9ca3af;text-align:center;padding:40px">No data entered for this month</p>'}
          <div style="text-align:center;padding-top:16px;border-top:1px solid #e5e7eb;font-size:11px;color:#9ca3af">
            Al-Methnab General Hospital — KPI Platform · Built by Anhal Mohammad
          </div>
        </div></body></html>`;

      const win = window.open('', '_blank');
      win.document.write(html);
      win.document.close();
    },
  };

  /* ═══════════════════════════════════
     BOOT — Initialize the application
     when the page finishes loading.
  ═══════════════════════════════════ */
  (function boot() {
    // Pre-load stored data so KPI entry has it ready
    KPIEntry.db = Store.load();
    // Load any admin-created custom departments into runtime arrays
    Manage.loadCustomDepts();
  })();
  /* ═══════════════════════════════════
     MANAGE — Admin controls for:
     1. Entry window (open/close + month)
     2. Custom department creation
     Persisted in localStorage so changes
     survive page refresh.
  ═══════════════════════════════════ */
  const Manage = {

    ENTRY_OPEN_KEY:    'kpi_entry_open',
    CUSTOM_DEPTS_KEY:  'kpi_custom_depts',
    CUSTOM_KPIS_KEY:   'kpi_custom_kpis',

    // ── Entry Window ────────────────────────────

    isEntryOpen() {
      const val = localStorage.getItem(this.ENTRY_OPEN_KEY);
      return val === null ? true : val === 'true';
    },

    toggleEntryWindow() {
      const current = this.isEntryOpen();
      localStorage.setItem(this.ENTRY_OPEN_KEY, !current);
      this._renderEntryStatus();
      Toast.show(current ? 'Staff entry closed' : 'Staff entry opened', current ? 'error' : 'success');
    },

    setOpenMonth(val) {
      Store.setOpenMonth(parseInt(val, 10));
      // Sync the dashboard control too
      const dashSel = document.getElementById('open-month-select');
      if (dashSel) dashSel.value = val;
      const badge = document.getElementById('open-month-badge');
      if (badge) badge.textContent = Config.MONTHS_FULL[parseInt(val, 10)] + ' — Open';
      Toast.show('Open month updated', 'success');
    },

    _renderEntryStatus() {
      const open = this.isEntryOpen();
      const btn  = document.getElementById('entry-toggle-btn');
      const desc = document.getElementById('entry-status-desc');
      if (btn) {
        btn.textContent = open ? 'Close Entry' : 'Open Entry';
        btn.style.background = open ? '#fee2e2' : '#dcfce7';
        btn.style.color      = open ? '#dc2626' : '#16a34a';
      }
      if (desc) {
        desc.textContent = open ? 'Staff can currently submit data' : 'Staff entry is closed';
        desc.style.color  = open ? 'var(--color-text-muted)' : '#dc2626';
      }
    },

    // ── KPI Row Builder ──────────────────────────

    _kpiRowCount: 0,

    addKPIRow() {
      const id = ++this._kpiRowCount;
      const container = document.getElementById('new-kpi-list');
      const row = document.createElement('div');
      row.id = `kpi-row-new-${id}`;
      row.style.cssText = 'display:grid;grid-template-columns:2fr 1fr 1fr 1fr auto;gap:8px;align-items:center';
      row.innerHTML = `
        <input placeholder="KPI Name" id="kn-${id}"
          style="border:1px solid var(--color-border);border-radius:8px;padding:8px 10px;font-size:12px;font-family:inherit;outline:none"/>
        <input placeholder="Target" id="kt-${id}" type="number" step="any"
          style="border:1px solid var(--color-border);border-radius:8px;padding:8px 10px;font-size:12px;font-family:inherit;outline:none"/>
        <input placeholder="Unit (%, days)" id="ku-${id}"
          style="border:1px solid var(--color-border);border-radius:8px;padding:8px 10px;font-size:12px;font-family:inherit;outline:none"/>
        <select id="kd-${id}"
          style="border:1px solid var(--color-border);border-radius:8px;padding:8px 6px;font-size:12px;font-family:inherit;outline:none;background:#fff">
          <option value="high">≥ High</option>
          <option value="low">≤ Low</option>
        </select>
        <button onclick="document.getElementById('kpi-row-new-${id}').remove()"
          style="background:none;border:none;cursor:pointer;color:#9ca3af;font-size:18px;padding:0 4px;line-height:1"
          title="Remove">×</button>`;
      container.appendChild(row);
    },

    // ── Save New Department ──────────────────────

    saveDept() {
      const nameEl = document.getElementById('new-dept-name');
      const idEl   = document.getElementById('new-dept-id');
      const name   = nameEl.value.trim();
      const rawId  = idEl.value.trim().toUpperCase().replace(/\s+/g, '_');

      if (!name || !rawId) {
        Toast.show('Please enter department name and abbreviation', 'error');
        return;
      }

      // Check for duplicate ID
      const allDepts = this._getCustomDepts();
      const builtIn  = ['ER','ICU','LAB','BED','PRIMARY','OPD','OR','DR','IC','NURSING','RADIOLOGY','MD','MORTUARY','HR','QM','C937'];
      if (builtIn.includes(rawId) || allDepts.some(d => d.id === rawId)) {
        Toast.show(`Department ID "${rawId}" already exists`, 'error');
        return;
      }

      // Collect KPIs from builder rows
      const kpis = [];
      let kpiIdx = 1;
      while (document.getElementById(`kpi-row-new-${kpiIdx}`) || kpiIdx <= this._kpiRowCount) {
        const kRow = document.getElementById(`kpi-row-new-${kpiIdx}`);
        if (kRow) {
          const kName = document.getElementById(`kn-${kpiIdx}`)?.value.trim();
          const kTgt  = parseFloat(document.getElementById(`kt-${kpiIdx}`)?.value);
          const kUnit = document.getElementById(`ku-${kpiIdx}`)?.value.trim() || '%';
          const kDir  = document.getElementById(`kd-${kpiIdx}`)?.value || 'high';
          if (kName && !isNaN(kTgt)) {
            kpis.push({ id: `custom_${rawId}_${kpiIdx}`, name: kName, unit: kUnit, target: kTgt, dir: kDir });
          }
        }
        kpiIdx++;
      }

      if (kpis.length === 0) {
        Toast.show('Add at least one KPI', 'error');
        return;
      }

      // Persist
      allDepts.push({ id: rawId, name: rawId, icon: 'qm' });
      localStorage.setItem(this.CUSTOM_DEPTS_KEY, JSON.stringify(allDepts));

      const customKPIs = this._getCustomKPIs();
      customKPIs[rawId] = kpis;
      localStorage.setItem(this.CUSTOM_KPIS_KEY, JSON.stringify(customKPIs));

      // Reload runtime arrays so new dept appears everywhere
      this._mergeIntoRuntime(rawId, kpis);

      // Reset form
      nameEl.value = '';
      idEl.value   = '';
      document.getElementById('new-kpi-list').innerHTML = '';
      this._kpiRowCount = 0;

      this._renderCustomDepts();
      this._buildMonthTabs('plans-month-tabs', this.selectedMonth, month => {
        this.selectedMonth = month;
        this._syncMonthTabs(month);
        AdminPlans.selectedMonth = month;
        AdminPlans.render();
      });
      DeptView.renderAdminGrid();
      AdminApp.renderDashboard();

      Toast.show(`Department "${rawId}" added successfully`, 'success');
    },

    /** Add custom dept + KPIs into the live runtime arrays */
    _mergeIntoRuntime(deptId, kpis) {
      if (!DEPARTMENTS.some(d => d.id === deptId)) {
        DEPARTMENTS.push({ id: deptId, name: deptId, icon: 'qm' });
      }
      KPIS_BY_DEPT[deptId] = kpis;
    },

    // ── Persistence helpers ──────────────────────

    _getCustomDepts() {
      try { return JSON.parse(localStorage.getItem(this.CUSTOM_DEPTS_KEY) || '[]'); } catch(_) { return []; }
    },

    _getCustomKPIs() {
      try { return JSON.parse(localStorage.getItem(this.CUSTOM_KPIS_KEY) || '{}'); } catch(_) { return {}; }
    },

    /** Load custom depts/KPIs into runtime on every page load */
    loadCustomDepts() {
      const depts = this._getCustomDepts();
      const kpis  = this._getCustomKPIs();
      depts.forEach(d => this._mergeIntoRuntime(d.id, kpis[d.id] || []));
    },

    // ── Render custom dept list ──────────────────

    _renderCustomDepts() {
      const container = document.getElementById('custom-dept-list');
      if (!container) return;
      const depts  = this._getCustomDepts();
      const kpis   = this._getCustomKPIs();
      if (depts.length === 0) {
        container.innerHTML = '<div style="font-size:13px;color:var(--color-text-muted);text-align:center;padding:20px">No custom departments added yet</div>';
        return;
      }
      container.innerHTML = depts.map(d => `
        <div style="display:flex;align-items:center;justify-content:space-between;padding:12px 14px;background:var(--color-bg);border-radius:8px;margin-bottom:8px">
          <div>
            <div style="font-size:13px;font-weight:700">${d.id}</div>
            <div style="font-size:11px;color:var(--color-text-muted);margin-top:2px">${(kpis[d.id]||[]).length} KPI${(kpis[d.id]||[]).length !== 1 ? 's' : ''}</div>
          </div>
          <button onclick="Manage.deleteDept('${d.id}')"
            style="background:var(--color-red-light);color:var(--color-red);border:none;border-radius:6px;padding:6px 12px;font-size:12px;font-weight:700;cursor:pointer;font-family:inherit">
            Delete
          </button>
        </div>`).join('');
    },

    deleteDept(deptId) {
      let depts = this._getCustomDepts().filter(d => d.id !== deptId);
      let kpis  = this._getCustomKPIs();
      delete kpis[deptId];
      localStorage.setItem(this.CUSTOM_DEPTS_KEY, JSON.stringify(depts));
      localStorage.setItem(this.CUSTOM_KPIS_KEY,  JSON.stringify(kpis));

      // Remove from runtime
      const idx = DEPARTMENTS.findIndex(d => d.id === deptId);
      if (idx > -1) DEPARTMENTS.splice(idx, 1);
      delete KPIS_BY_DEPT[deptId];

      this._renderCustomDepts();
      this._buildMonthTabs('plans-month-tabs', this.selectedMonth, month => {
        this.selectedMonth = month;
        this._syncMonthTabs(month);
        AdminPlans.selectedMonth = month;
        AdminPlans.render();
      });
      DeptView.renderAdminGrid();
      AdminApp.renderDashboard();
      Toast.show(`Department "${deptId}" deleted`, 'info');
    },

    // ── Init (called when page opens) ────────────

    init() {
      this._renderEntryStatus();
      this._renderCustomDepts();

      // Populate month select
      const sel = document.getElementById('manage-month-select');
      if (sel) {
        const cur = Store.getOpenMonth();
        sel.innerHTML = Config.MONTHS_SHORT
          .map((m,i) => `<option value="${i}" ${i===cur?'selected':''}>${m}</option>`)
          .join('');
      }
    },
  };

  /* ═══════════════════════════════════
     CORRECTIVE PLAN — Staff side.
     After saving KPIs, if any are below
     standard the staff sees a form to
     describe their corrective action for
     each failing KPI. Plans are saved to
     localStorage (and synced to Sheets).
  ═══════════════════════════════════ */
  const CorrectivePlan = {

    PLANS_KEY: 'kpi_plans_v1',

    /** Load all plans from localStorage */
    loadAll() {
      try { return JSON.parse(localStorage.getItem(this.PLANS_KEY) || '{}'); } catch(_) { return {}; }
    },

    /** Save all plans to localStorage */
    saveAll(plans) {
      try { localStorage.setItem(this.PLANS_KEY, JSON.stringify(plans)); } catch(_) {}
    },

    /**
     * After KPI data is saved, check for failing/distress KPIs
     * and render the corrective plan form.
     */
    renderAfterSave(deptId, month) {
      const db       = Store.load();
      const key      = Store.buildKey(deptId, Config.YEAR, month);
      const saved    = db[key] ?? {};
      const kpis     = KPIUtils.getKPIsForDept(deptId);
      const allPlans = this.loadAll();
      const planKey  = `${deptId}-${Config.YEAR}-${month}`;
      const existing = allPlans[planKey] ?? {};

      // Filter KPIs that need a plan (distress, failing, failed)
      const needsPlan = kpis.filter(kpi => {
        const status = KPIUtils.getStatus(kpi, saved[kpi.id]);
        return ['distress', 'failing', 'failed'].includes(status);
      });

      const section = document.getElementById('corrective-plan-section');
      const list    = document.getElementById('corrective-plan-list');

      if (needsPlan.length === 0) {
        if (section) section.style.display = 'none';
        return;
      }

      if (section) section.style.display = 'block';

      list.innerHTML = needsPlan.map(kpi => {
        const status   = KPIUtils.getStatus(kpi, saved[kpi.id]);
        const val      = saved[kpi.id] ?? '';
        const existing_plan = existing[kpi.id]?.plan ?? '';
        const existing_due  = existing[kpi.id]?.due  ?? '';
        const dir      = kpi.dir === 'high' ? '≥' : '≤';

        return `
          <div class="plan-entry-item">
            <div class="plan-entry-item__kpi">
              ${kpi.name}
              <span class="plan-entry-item__kpi-status ${status}">${KPIUtils.getStatusLabel(status)}</span>
            </div>
            <div class="plan-entry-item__value">
              Actual: <strong>${val !== '' ? val + ' ' + kpi.unit : 'No data'}</strong>
              &nbsp;·&nbsp; Target: ${dir}${kpi.target} ${kpi.unit}
            </div>
            <textarea
              class="plan-textarea"
              id="plan-text-${kpi.id}"
              placeholder="Describe the corrective action you will take to improve this KPI..."
            >${existing_plan}</textarea>
            <div class="plan-due-row">
              <span class="plan-due-label">Target completion date:</span>
              <input type="date" class="plan-due-input" id="plan-due-${kpi.id}" value="${existing_due}"/>
            </div>
          </div>`;
      }).join('');

      // Store which KPIs need plans for the save method
      list.dataset.deptId = deptId;
      list.dataset.month  = month;
      list.dataset.kpis   = JSON.stringify(needsPlan.map(k => k.id));
    },

    /** Save all entered corrective plans */
    save() {
      const list    = document.getElementById('corrective-plan-list');
      const deptId  = list.dataset.deptId;
      const month   = parseInt(list.dataset.month, 10);
      const kpiIds  = JSON.parse(list.dataset.kpis || '[]');
      const planKey = `${deptId}-${Config.YEAR}-${month}`;

      const allPlans = this.loadAll();
      if (!allPlans[planKey]) allPlans[planKey] = {};

      let hasEmpty = false;

      kpiIds.forEach(id => {
        const text = document.getElementById(`plan-text-${id}`)?.value.trim() ?? '';
        const due  = document.getElementById(`plan-due-${id}`)?.value ?? '';

        if (!text) { hasEmpty = true; return; }

        allPlans[planKey][id] = {
          plan:       text,
          due:        due,
          status:     'pending',
          adminNote:  '',
          submittedAt: new Date().toISOString(),
          dept:       deptId,
          month:      month,
          year:       Config.YEAR,
        };
      });

      if (hasEmpty) {
        Toast.show('Please fill in all corrective plan fields', 'error');
        return;
      }

      this.saveAll(allPlans);

      const btn = document.getElementById('plan-save-btn');
      btn.textContent = 'Plans Submitted';
      btn.style.background = 'var(--color-green)';
      btn.disabled = true;

      Toast.show('Corrective plans submitted successfully', 'success');

      setTimeout(() => {
        btn.textContent = 'Submit Corrective Plans';
        btn.style.background = '';
        btn.disabled = false;
      }, 3000);
    },
  };

  /* ═══════════════════════════════════
     ADMIN PLANS — Admin side.
     Shows all submitted corrective plans,
     lets admin filter by status and update
     each plan with a note and new status.
  ═══════════════════════════════════ */
  const AdminPlans = {

    currentFilter: 'all',
    selectedMonth: null,

    init(month) {
      this.selectedMonth = month ?? AdminApp.selectedMonth;
      this.currentFilter = 'all';
      this._setActiveFilter('all');
      this.render();
    },

    filterBy(status) {
      this.currentFilter = status;
      this._setActiveFilter(status);
      this.render();
    },

    _setActiveFilter(status) {
      ['all','pending','in_progress','resolved'].forEach(s => {
        const btn = document.getElementById(`filter-${s}`);
        if (btn) btn.classList.toggle('active', s === status);
      });
    },

    render() {
      const container = document.getElementById('plans-content');
      if (!container) return;

      const allPlans = CorrectivePlan.loadAll();
      const db       = Store.load();

      // Collect all plan entries for the selected month
      const entries = [];
      DEPARTMENTS.forEach(dept => {
        const planKey = `${dept.id}-${Config.YEAR}-${this.selectedMonth}`;
        const deptPlans = allPlans[planKey] ?? {};

        Object.entries(deptPlans).forEach(([kpiId, planData]) => {
          const kpis = KPIUtils.getKPIsForDept(dept.id);
          const kpi  = kpis.find(k => k.id === kpiId);
          if (!kpi) return;

          entries.push({
            deptId:   dept.id,
            deptName: dept.name,
            planKey,
            kpiId,
            kpi,
            ...planData,
          });
        });
      });

      // Apply filter
      const filtered = this.currentFilter === 'all'
        ? entries
        : entries.filter(e => e.status === this.currentFilter);

      if (filtered.length === 0) {
        container.innerHTML = `
          <div class="plans-empty">
            <svg viewBox="0 0 24 24"><path d="M9 11l3 3L22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/></svg>
            <p>${this.currentFilter === 'all'
              ? 'No corrective plans submitted for ' + Config.MONTHS_FULL[this.selectedMonth]
              : 'No ' + this.currentFilter.replace('_', ' ') + ' plans'
            }</p>
          </div>`;
        return;
      }

      // Group by department
      const byDept = {};
      filtered.forEach(e => {
        if (!byDept[e.deptId]) byDept[e.deptId] = { name: e.deptName, plans: [] };
        byDept[e.deptId].plans.push(e);
      });

      container.innerHTML = Object.entries(byDept).map(([deptId, group]) => `
        <div style="margin-bottom:24px">
          <div style="font-size:12px;font-weight:700;color:var(--color-text-muted);text-transform:uppercase;letter-spacing:.07em;margin-bottom:10px;display:flex;align-items:center;gap:6px">
            <span>${deptId}</span>
            <span style="background:var(--color-bg);color:var(--color-text-muted);font-size:10px;padding:2px 8px;border-radius:20px">${group.plans.length} plan${group.plans.length !== 1 ? 's' : ''}</span>
          </div>
          ${group.plans.map(e => this._buildCard(e)).join('')}
        </div>`).join('');
    },

    _buildCard(entry) {
      const statusLabel = { pending: 'Pending', in_progress: 'In Progress', resolved: 'Resolved' };
      const dueDisplay  = entry.due
        ? new Date(entry.due).toLocaleDateString('en-GB')
        : 'No date set';
      const submittedDisplay = entry.submittedAt
        ? new Date(entry.submittedAt).toLocaleDateString('en-GB')
        : '—';

      return `
        <div class="plan-card status-${entry.status}" id="plan-card-${entry.deptId}-${entry.kpiId}">
          <div class="plan-card__header">
            <div>
              <div class="plan-card__kpi-name">${entry.kpi.name}</div>
              <div class="plan-card__meta">
                <span><svg viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg> Due: ${dueDisplay}</span>
                <span><svg viewBox="0 0 24 24"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg> Submitted: ${submittedDisplay}</span>
              </div>
            </div>
            <span class="plan-status-badge ${entry.status}">${statusLabel[entry.status] ?? entry.status}</span>
          </div>

          <div class="plan-card__body">
            <div class="plan-card__label">Staff Corrective Plan</div>
            <div class="plan-card__text">${entry.plan}</div>
          </div>

          ${entry.adminNote ? `
          <div class="plan-card__body" style="background:#f0f9ff;border:1px solid #bae6fd">
            <div class="plan-card__label" style="color:#0369a1">Admin Note</div>
            <div class="plan-card__text">${entry.adminNote}</div>
          </div>` : ''}

          <div class="plan-card__actions">
            <input class="plan-card__admin-note" type="text"
              id="admin-note-${entry.deptId}-${entry.kpiId}"
              placeholder="Add admin note or feedback..."
              value="${entry.adminNote ?? ''}"/>
            <select class="plan-status-select" id="plan-status-${entry.deptId}-${entry.kpiId}">
              <option value="pending"     ${entry.status === 'pending'     ? 'selected' : ''}>Pending</option>
              <option value="in_progress" ${entry.status === 'in_progress' ? 'selected' : ''}>In Progress</option>
              <option value="resolved"    ${entry.status === 'resolved'    ? 'selected' : ''}>Resolved</option>
            </select>
            <button class="plan-update-btn"
              onclick="AdminPlans.update('${entry.deptId}','${entry.kpiId}','${entry.planKey}')">
              Update
            </button>
          </div>
        </div>`;
    },

    update(deptId, kpiId, planKey) {
      const note   = document.getElementById(`admin-note-${deptId}-${kpiId}`)?.value.trim() ?? '';
      const status = document.getElementById(`plan-status-${deptId}-${kpiId}`)?.value ?? 'pending';

      const allPlans = CorrectivePlan.loadAll();
      if (!allPlans[planKey]?.[kpiId]) return;

      allPlans[planKey][kpiId].adminNote  = note;
      allPlans[planKey][kpiId].status     = status;
      allPlans[planKey][kpiId].updatedAt  = new Date().toISOString();

      CorrectivePlan.saveAll(allPlans);
      this.render();
      Toast.show('Plan updated', 'success');
    },
  };
